(()=>{"use strict";document.addEventListener("DOMContentLoaded",()=>{const t=document.querySelector("#stagify-test-connection"),e=document.querySelector("#stagify-test-result");t&&e&&t.addEventListener("click",async()=>{t.disabled=!0,e.textContent="",e.removeAttribute("style");try{const t=new URLSearchParams({action:"stagify_test_connection",_ajax_nonce:stagifySettings.nonce}),n=await fetch(stagifySettings.ajaxUrl,{method:"POST",credentials:"same-origin",body:t}),s=await n.json();e.textContent=s.message,e.style.color=s.success?"#46b450":"#dc3232",e.style.fontWeight="600",e.style.marginLeft="10px"}catch{e.textContent="Request failed. Check your network.",e.style.color="#dc3232",e.style.fontWeight="600",e.style.marginLeft="10px"}finally{t.disabled=!1}})})})();